"""Authentication helpers for the AgentOS composition root."""

from __future__ import annotations

import hashlib
import json
import tempfile
from pathlib import Path
from typing import Any
from urllib.parse import urlparse

import requests
from agno.os.config import AuthorizationConfig

from agno_platform.settings import AuthSettings

_DEFAULT_JWKS_CACHE_DIR = Path(tempfile.gettempdir()) / "agentos-jwks-cache"
_JWKS_FETCH_TIMEOUT_SECONDS = 30
_AGNO_OS_RSA_ALGORITHM = "RS256"


def materialize_jwks_file(jwks_url: str, *, cache_dir: Path | None = None) -> str:
    """Download Supabase JWKS and return a local path for Agno's JWTValidator.

    Agno's ``AuthorizationConfig.jwks_file`` is a filesystem path only (not a URL).
    """
    parsed = urlparse(jwks_url)
    if parsed.scheme != "https" or not parsed.netloc:
        raise ValueError(f"SUPABASE_JWKS_URL must be an https URL, got: {jwks_url!r}")

    cache_root = cache_dir or _DEFAULT_JWKS_CACHE_DIR
    cache_root.mkdir(parents=True, exist_ok=True)
    url_hash = hashlib.sha256(jwks_url.encode()).hexdigest()[:16]
    cache_path = cache_root / f"supabase-jwks-{url_hash}.json"

    try:
        response = requests.get(jwks_url, timeout=_JWKS_FETCH_TIMEOUT_SECONDS)
        response.raise_for_status()
        raw = response.content
    except requests.RequestException as exc:
        raise RuntimeError(f"Failed to fetch JWKS from {jwks_url}: {exc}") from exc

    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise RuntimeError(f"JWKS response from {jwks_url} is not valid JSON: {exc}") from exc

    if not isinstance(payload.get("keys"), list) or not payload["keys"]:
        raise RuntimeError(f"JWKS response from {jwks_url} has no keys")

    cache_path.write_bytes(raw)
    return str(cache_path)


def infer_jwks_algorithms(jwks_path: str) -> list[str]:
    """Return distinct ``alg`` values from a JWKS file (e.g. ``ES256`` for Supabase)."""
    payload = json.loads(Path(jwks_path).read_text(encoding="utf-8"))
    keys = payload.get("keys", [])
    if not isinstance(keys, list):
        return [_AGNO_OS_RSA_ALGORITHM]

    algorithms: list[str] = []
    for key_data in keys:
        if not isinstance(key_data, dict):
            continue
        alg = key_data.get("alg")
        if isinstance(alg, str) and alg and alg not in algorithms:
            algorithms.append(alg)

    return algorithms or [_AGNO_OS_RSA_ALGORITHM]


def resolve_authorization_algorithm(
    *,
    jwks_path: str | None,
    has_pem_keys: bool,
) -> str:
    """Build the ``algorithm`` field for ``AuthorizationConfig``.

    Agno's ``JWTValidator`` accepts only one algorithm string, but comma-separated
    values are supported via :func:`_patch_jwt_validator_for_multi_algorithm` so
    Supabase (typically ES256 JWKS) and os.agno.com (RS256 PEM) can coexist.
    """
    if jwks_path is None:
        return _AGNO_OS_RSA_ALGORITHM

    jwks_algorithms = infer_jwks_algorithms(jwks_path)
    if not has_pem_keys:
        return jwks_algorithms[0]

    combined = list(jwks_algorithms)
    if _AGNO_OS_RSA_ALGORITHM not in combined:
        combined.append(_AGNO_OS_RSA_ALGORITHM)
    return ",".join(combined)


def _patch_jwt_validator_for_multi_algorithm() -> None:
    """Allow ``AuthorizationConfig.algorithm`` to be comma-separated (e.g. ``ES256,RS256``).

    Upstream Agno passes ``algorithms=[self.algorithm]`` as a single entry, which
    rejects Supabase ES256 tokens when the config says ``RS256``.
    """
    from agno.os.middleware.jwt import JWTValidator

    if getattr(JWTValidator, "_multi_algorithm_patch_applied", False):
        return

    _original_validate_token = JWTValidator.validate_token

    def validate_token(
        self: JWTValidator,
        token: str,
        expected_audience: str | Any | None = None,
    ) -> dict[str, Any]:
        if self.algorithm and "," in self.algorithm:
            allowed_algorithms = [part.strip() for part in self.algorithm.split(",") if part.strip()]
            if len(allowed_algorithms) > 1:
                return _validate_token_with_algorithms(
                    self,
                    token,
                    allowed_algorithms,
                    expected_audience,
                )
        return _original_validate_token(self, token, expected_audience)

    JWTValidator.validate_token = validate_token  # type: ignore[method-assign]
    JWTValidator._multi_algorithm_patch_applied = True


def _validate_token_with_algorithms(
    validator: Any,
    token: str,
    algorithms: list[str],
    expected_audience: Any,
) -> dict[str, Any]:
    """Same flow as Agno's ``JWTValidator.validate_token`` with multiple algorithms."""
    import jwt

    decode_options: dict[str, Any] = {}
    decode_kwargs: dict[str, Any] = {
        "algorithms": algorithms,
        "leeway": validator.leeway,
    }
    decode_options["verify_aud"] = False

    if not validator.validate:
        decode_options["verify_signature"] = False
        decode_kwargs["options"] = decode_options
        return jwt.decode(token, **decode_kwargs)

    if decode_options:
        decode_kwargs["options"] = decode_options

    last_exception: Exception | None = None
    payload: dict[str, Any] | None = None

    if validator.jwks_keys:
        try:
            unverified_header = jwt.get_unverified_header(token)
            kid = unverified_header.get("kid")

            jwk = None
            if kid and kid in validator.jwks_keys:
                jwk = validator.jwks_keys[kid]
            elif "_default" in validator.jwks_keys:
                jwk = validator.jwks_keys["_default"]

            if jwk:
                payload = jwt.decode(token, jwk.key, **decode_kwargs)
        except jwt.ExpiredSignatureError:
            raise
        except jwt.InvalidTokenError as e:
            if not validator.verification_keys:
                raise
            last_exception = e

    if payload is None:
        for key in validator.verification_keys:
            try:
                payload = jwt.decode(token, key, **decode_kwargs)
                break
            except jwt.ExpiredSignatureError:
                raise
            except jwt.InvalidTokenError as e:
                last_exception = e
                continue

    if payload is None:
        if last_exception:
            raise last_exception
        raise jwt.InvalidTokenError("No verification keys configured")

    if expected_audience:
        token_audience = payload.get(validator.audience_claim)
        if token_audience is None:
            raise jwt.InvalidTokenError(
                f'Token is missing the "{validator.audience_claim}" claim. '
                "Audience verification requires this claim to be present in the token."
            )

        if isinstance(expected_audience, str):
            expected_audiences = [expected_audience]
        else:
            expected_audiences = list(expected_audience)

        if isinstance(token_audience, str):
            token_audiences = [token_audience]
        elif isinstance(token_audience, list):
            token_audiences = token_audience
        else:
            token_audiences = [token_audience] if token_audience else []

        if not any(aud in expected_audiences for aud in token_audiences):
            raise jwt.InvalidAudienceError(
                f"Invalid audience. Expected one of: {expected_audiences}, got: {token_audiences}"
            )

    return payload


_patch_jwt_validator_for_multi_algorithm()


def _authorization_common(auth: AuthSettings) -> dict[str, Any]:
    return {
        "verify_audience": False,
        "audience": auth.audience,
        "admin_scope": auth.admin_scope,
        "user_isolation": False,
    }


def build_authorization_config(auth: AuthSettings) -> AuthorizationConfig:
    """Translate AuthSettings into the AuthorizationConfig shape Agno expects."""
    common = _authorization_common(auth)
    pem_keys = auth.verification_keys or None

    if auth.jwks_url:
        jwks_path = materialize_jwks_file(auth.jwks_url)
        algorithm = resolve_authorization_algorithm(
            jwks_path=jwks_path,
            has_pem_keys=bool(pem_keys),
        )
        return AuthorizationConfig(
            jwks_file=jwks_path,
            verification_keys=pem_keys,
            algorithm=algorithm,
            **common,
        )

    if auth.jwt_secret is not None:
        return AuthorizationConfig(
            verification_keys=[auth.jwt_secret],
            algorithm="HS256",
            **common,
        )

    if not pem_keys:
        raise RuntimeError("verification_keys is empty — AuthSettings invariant violated")

    return AuthorizationConfig(
        verification_keys=pem_keys,
        algorithm=_AGNO_OS_RSA_ALGORITHM,
        **common,
    )

