def load_jwks_file(jwks_path: str) -> str:
    """Validate a local JWKS file and return its absolute path for Agno's JWTValidator."""
    path = Path(jwks_path).expanduser()
    if not path.is_file():
        raise ValueError(f"SUPABASE_JWKS_FILE not found: {jwks_path!r}")

    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise ValueError(f"SUPABASE_JWKS_FILE is not valid JSON ({path}): {exc}") from exc

    _validate_jwks_payload(payload, source=str(path))
    return str(path.resolve())


